-- crew_meals_taxonomy_micro_category
--
-- Adds the "Crew Meals" micro-category tile under FEAST + its `crew_meal_supply`
-- canonical service (owner-locked 2026-07-08 — the Crew-Meal Provider Marketplace:
-- nearby kitchens supply the event CREW's packed meals, decoupled from the guests'
-- main caterer). Source of truth is `apps/web/lib/taxonomy.ts`; this SQL is the
-- REGENERATED full seed emitted by `apps/web/scripts/gen-taxonomy-seed.ts`
-- (10 parents + 57 tiles · 232 canonical mappings). Re-emitting the whole seed
-- keeps `service_categories` + `canonical_service_taxonomy` in lockstep with code
-- and re-numbers `sort_order` after the new tile (index 7, between Stations and
-- Stylist / Decorator). Idempotent — every row is INSERT … ON CONFLICT DO UPDATE.
--
-- DO NOT HAND-EDIT the VALUES below — re-run the generator after any TAXONOMY_MAP
-- change and replace this block:
--   cd apps/web && npx tsx scripts/gen-taxonomy-seed.ts

ON CONFLICT (id) DO UPDATE SET
  parent_id   = EXCLUDED.parent_id,
  tier        = EXCLUDED.tier,
  kind        = EXCLUDED.kind,
  label_en    = EXCLUDED.label_en,
  label_short = EXCLUDED.label_short,
  slug        = EXCLUDED.slug,
  sort_order  = EXCLUDED.sort_order,
  updated_at  = now();

ON CONFLICT (canonical_service) DO UPDATE SET
  folder_id          = EXCLUDED.folder_id,
  tile_id            = EXCLUDED.tile_id,
  phase              = EXCLUDED.phase,
  faith              = EXCLUDED.faith,
  is_ph              = EXCLUDED.is_ph,
  is_setnayan        = EXCLUDED.is_setnayan,
  is_rental          = EXCLUDED.is_rental,
  dietary            = EXCLUDED.dietary,
  is_tradition       = EXCLUDED.is_tradition,
  marketplace_hidden = EXCLUDED.marketplace_hidden,
  secondary_tiles    = EXCLUDED.secondary_tiles,
  updated_at         = now();
